package ingest

import (
	"fmt"
	"strings"

	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"
)

// ParseOptions configures the markdown parser.
type ParseOptions struct {
	MaxChunkSize int
	Scope        string
	Kind         string
}

// Parse splits markdown content into section-level chunks.
// Splits on ## headers. # is document title (metadata). ### and deeper
// are included within their parent ## section.
func Parse(path, content string, opts ParseOptions) []domain.Chunk {
	if opts.MaxChunkSize <= 0 {
		opts.MaxChunkSize = 16000
	}

	slug := domain.SlugFromPath(path)
	fm, body := ExtractFrontMatter(content)

	// Determine effective scope and kind (front matter overrides parameters)
	scope := opts.Scope
	if fm.Scope != "" {
		scope = fm.Scope
	}
	kind := opts.Kind
	if fm.Kind != "" {
		kind = fm.Kind
	}
	tags := fm.Tags
	if tags == nil {
		tags = []string{}
	}

	// Extract document title from # heading if no front matter title
	docTitle := fm.Title

	lines := strings.Split(body, "\n")
	type section struct {
		heading string
		content []string
	}

	var sections []section
	var preamble []string
	var current *section

	for _, line := range lines {
		if strings.HasPrefix(line, "# ") && !strings.HasPrefix(line, "## ") {
			// H1: document title, not a section
			if docTitle == "" {
				docTitle = strings.TrimPrefix(line, "# ")
				docTitle = strings.TrimSpace(docTitle)
			}
			continue
		}

		if strings.HasPrefix(line, "## ") && !strings.HasPrefix(line, "### ") {
			// New ## section
			if current != nil {
				sections = append(sections, *current)
			}
			heading := strings.TrimPrefix(line, "## ")
			heading = strings.TrimSpace(heading)
			current = &section{heading: heading, content: []string{}}
			continue
		}

		if current != nil {
			current.content = append(current.content, line)
		} else {
			preamble = append(preamble, line)
		}
	}

	// Flush last section
	if current != nil {
		sections = append(sections, *current)
	}

	// If no ## sections found, treat entire body as one chunk
	if len(sections) == 0 {
		sectionContent := strings.TrimSpace(body)
		if sectionContent == "" {
			return nil
		}
		sectionID := "content"
		title := docTitle
		if title == "" {
			title = slug
		}
		return []domain.Chunk{{
			QualifiedID:  domain.QualifiedID(slug, sectionID),
			SectionID:    sectionID,
			DocumentSlug: slug,
			Title:        title,
			Content:      sectionContent,
			Scope:        scope,
			Kind:         kind,
			Tags:         tags,
			Position:     0,
		}}
	}

	var chunks []domain.Chunk
	position := 0

	// Include preamble as a chunk if non-trivial
	preambleText := strings.TrimSpace(strings.Join(preamble, "\n"))
	if len(preambleText) > 50 {
		sectionID := "preamble"
		title := docTitle
		if title == "" {
			title = "Preamble"
		}
		chunks = append(chunks, domain.Chunk{
			QualifiedID:  domain.QualifiedID(slug, sectionID),
			SectionID:    sectionID,
			DocumentSlug: slug,
			Title:        title,
			Content:      preambleText,
			Scope:        scope,
			Kind:         kind,
			Tags:         tags,
			Position:     position,
		})
		position++
	}

	for _, sec := range sections {
		sectionID, title := ExtractSectionID(sec.heading)
		if title == "" {
			title = sec.heading
		}
		sectionContent := strings.TrimSpace(strings.Join(sec.content, "\n"))

		// Sub-split if content exceeds maxChunkSize
		if len(sectionContent) > opts.MaxChunkSize {
			subChunks := subSplit(sectionContent, opts.MaxChunkSize)
			for i, sub := range subChunks {
				subID := fmt.Sprintf("%s#%d", sectionID, i+1)
				subTitle := title
				if len(subChunks) > 1 {
					subTitle = fmt.Sprintf("%s (part %d)", title, i+1)
				}
				chunks = append(chunks, domain.Chunk{
					QualifiedID:  domain.QualifiedID(slug, subID),
					SectionID:    subID,
					DocumentSlug: slug,
					Title:        subTitle,
					Content:      sub,
					Scope:        scope,
					Kind:         kind,
					Tags:         tags,
					Position:     position,
				})
				position++
			}
		} else {
			chunks = append(chunks, domain.Chunk{
				QualifiedID:  domain.QualifiedID(slug, sectionID),
				SectionID:    sectionID,
				DocumentSlug: slug,
				Title:        title,
				Content:      sectionContent,
				Scope:        scope,
				Kind:         kind,
				Tags:         tags,
				Position:     position,
			})
			position++
		}
	}

	return chunks
}

// subSplit divides long content at paragraph boundaries.
func subSplit(content string, maxSize int) []string {
	paragraphs := strings.Split(content, "\n\n")
	var result []string
	var current strings.Builder

	for _, para := range paragraphs {
		if current.Len() > 0 && current.Len()+len(para)+2 > maxSize {
			result = append(result, strings.TrimSpace(current.String()))
			current.Reset()
		}
		if current.Len() > 0 {
			current.WriteString("\n\n")
		}
		current.WriteString(para)
	}

	if current.Len() > 0 {
		result = append(result, strings.TrimSpace(current.String()))
	}

	// Safety: if a single paragraph exceeds maxSize, it stays as one chunk
	if len(result) == 0 {
		result = []string{content}
	}

	return result
}
